"use client"

import { useState } from "react"
import Link from "next/link"
import { useAuth } from "@/contexts/auth-context"
import { useTheme } from "@/contexts/theme-context"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { 
  Truck, 
  Settings, 
  LogOut, 
  User, 
  Sun, 
  Moon, 
  Eye,
  Menu,
  X,
  ShoppingCart,
  Phone,
  Wrench
} from "lucide-react"

export function Header() {
  const { user, logout, isAdmin } = useAuth()
  const { theme, setTheme } = useTheme()
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)

  const themeOptions = [
    { value: "light" as const, label: "Modo Claro", icon: Sun },
    { value: "dark" as const, label: "Modo Oscuro", icon: Moon },
    { value: "colorblind" as const, label: "Modo Daltónico", icon: Eye },
  ]

  return (
    <header className="sticky top-0 z-50 w-full border-b border-border bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
      <div className="container mx-auto px-4">
        <div className="flex h-16 items-center justify-between">
          {/* Logo */}
          <Link href="/dashboard" className="flex items-center gap-3">
            <img src="/logo_gear.png?v=2" alt="TruckParts Pro" className="h-10 w-auto object-contain" />
            <span className="text-xl font-bold text-foreground">Truck Parts Pro</span>
          </Link>

          {/* Desktop Navigation */}
          <nav className="hidden md:flex items-center gap-6">
            <Link 
              href="/dashboard" 
              className="text-sm font-medium text-foreground hover:opacity-80 transition-colors"
            >
              Inicio
            </Link>
            <Link 
              href="/dashboard#productos" 
              className="text-sm font-medium text-foreground hover:opacity-80 transition-colors"
            >
              Productos
            </Link>
            <Link 
              href="/dashboard#servicios" 
              className="text-sm font-medium text-foreground hover:opacity-80 transition-colors"
            >
              Servicios
            </Link>
            <Link 
              href="/dashboard#contacto" 
              className="text-sm font-medium text-foreground hover:opacity-80 transition-colors"
            >
              Contacto
            </Link>
          </nav>

          {/* Right Side Actions */}
          <div className="flex items-center gap-2">

            {/* ⚙️ Settings Gear — unified settings menu */}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  className="text-foreground relative"
                  title="Ajustes"
                >
                  <Settings className="h-5 w-5 transition-transform duration-300 hover:rotate-90" />
                  <span className="sr-only">Ajustes</span>
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-56 bg-white/10 backdrop-blur-2xl border border-white/20 shadow-2xl p-2 rounded-2xl">
                {/* Theme section */}
                <DropdownMenuLabel className="flex items-center gap-2 px-2 py-1.5 text-sm font-semibold text-white/70">
                  <Moon className="h-4 w-4" />
                  Apariencia
                </DropdownMenuLabel>
                
                {themeOptions.map((option) => (
                  <DropdownMenuItem
                    key={option.value}
                    onClick={() => setTheme(option.value)}
                    className={`flex items-center gap-2 cursor-pointer rounded-xl transition-all duration-300 px-3 py-2.5 ${
                      theme === option.value 
                        ? "bg-white/20 text-white font-medium" 
                        : "hover:bg-white/5 text-white/90"
                    }`}
                  >
                    <option.icon className={`h-4 w-4 ${theme === option.value ? "text-white" : "text-white/60"}`} />
                    <span>{option.label}</span>
                    {theme === option.value && (
                      <span className="ml-auto text-white">✓</span>
                    )}
                  </DropdownMenuItem>
                ))}

                {/* Admin section — only visible to admins */}
                {isAdmin && (
                  <>
                    <DropdownMenuSeparator className="bg-white/10 my-2" />
                    <DropdownMenuItem asChild>
                      <Link 
                        href="/admin" 
                        className="flex items-center gap-2 cursor-pointer rounded-xl transition-all duration-300 px-3 py-2.5 hover:bg-white/5 text-white/90"
                      >
                        <Settings className="h-4 w-4 text-white/60" />
                        <span>Panel de Admin</span>
                      </Link>
                    </DropdownMenuItem>
                  </>
                )}
              </DropdownMenuContent>
            </DropdownMenu>

            {/* User Menu */}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" size="icon" className="text-foreground">
                  <User className="h-5 w-5" />
                  <span className="sr-only">Menú de usuario</span>
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-56 bg-white/10 backdrop-blur-2xl border border-white/20 shadow-2xl p-2 rounded-2xl text-white">
                <DropdownMenuLabel className="font-normal px-2 py-1.5 text-white/70">
                  <div className="flex flex-col space-y-1">
                    <p className="text-sm font-medium text-white">{user?.name}</p>
                    <p className="text-xs text-white/60">{user?.email}</p>
                    <span className="inline-flex items-center mt-1 px-2 py-0.5 rounded-full text-[10px] font-bold bg-white/20 text-white w-fit">
                      {isAdmin ? "Administrador" : "Usuario"}
                    </span>
                  </div>
                </DropdownMenuLabel>
                <DropdownMenuSeparator className="bg-white/10 my-2" />
                <DropdownMenuItem 
                  onClick={logout} 
                  className="flex items-center gap-2 cursor-pointer rounded-xl transition-all duration-300 px-3 py-2.5 hover:bg-white/5 text-white/90"
                >
                  <LogOut className="h-4 w-4 text-white/60" />
                  <span>Cerrar Sesión</span>
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>

            {/* Mobile Menu Button */}
            <Button
              variant="ghost"
              size="icon"
              className="md:hidden text-foreground"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            >
              {mobileMenuOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
            </Button>
          </div>
        </div>

        {/* Mobile Navigation */}
        {mobileMenuOpen && (
          <div className="md:hidden py-4 border-t border-border">
            <nav className="flex flex-col gap-2">
              <Link 
                href="/dashboard" 
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-muted rounded-lg transition-colors"
                onClick={() => setMobileMenuOpen(false)}
              >
                <Truck className="h-4 w-4" />
                Inicio
              </Link>
              <Link 
                href="/dashboard#productos" 
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-muted rounded-lg transition-colors"
                onClick={() => setMobileMenuOpen(false)}
              >
                <ShoppingCart className="h-4 w-4" />
                Productos
              </Link>
              <Link 
                href="/dashboard#servicios" 
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-muted rounded-lg transition-colors"
                onClick={() => setMobileMenuOpen(false)}
              >
                <Wrench className="h-4 w-4" />
                Servicios
              </Link>
              <Link 
                href="/dashboard#contacto" 
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-muted rounded-lg transition-colors"
                onClick={() => setMobileMenuOpen(false)}
              >
                <Phone className="h-4 w-4" />
                Contacto
              </Link>
            </nav>
          </div>
        )}
      </div>
    </header>
  )
}
